parameters.jsCode:
// 1. Ambil teks JSON dari node Extract
let rawText = $input.all()[0].json.text || "";

// 2. Bersihkan backtick markdown jika terbawa oleh sistem
rawText = rawText.replace(/```json/g, '').replace(/```/g, '').trim();

let data;
try {
  data = JSON.parse(rawText);
} catch (error) {
  return [{ json: { error: "Gagal membaca JSON", raw: rawText } }];
}

let rows = data.rows || [];

// 3. Deteksi Ganjil/Genap otomatis dari judul dokumen
let semesterStr = "Genap (Semester 2, 4, 6, 8)";
if (data.document_title && data.document_title.toUpperCase().includes("GANJIL")) {
  semesterStr = "Ganjil (Semester 1, 3, 5, 7)";
}

let results = [];

// 4. Looping untuk membuat blok Markdown per kelas!
for (let row of rows) {

  // Gabungkan nama dosen, buang yang null
  let dosenList = [row.dosen_1, row.dosen_2, row.dosen_3]
    .filter(d => d !== null && d !== "" && d !== "null")
    .join(", ");

  // Template Markdown super rapi
  let markdownBlock = `Mata Kuliah: ${row.mata_kuliah}
Kelas: ${row.kelas}
Kode MK: ${row.kode_mk}
Hari: ${row.hari}
Jam: ${row.jam}
Dosen Pengampu: ${dosenList}
Ruangan: ${row.ruang}
Program Studi: Teknik Informatika
Semester: ${semesterStr}`;

  // Jadikan ini sebagai 1 item mandiri untuk Pinecone
  results.push({
    json: {
      text: markdownBlock
    }
  });
}

// Mengeluarkan puluhan/ratusan blok jadwal secara rapi!
return results;

